#include <iostream>
#include <unordered_map>
#include <string>
#include <chrono>
#include <memory>

class Session {
public:
    std::string sessionId;
    std::string data;
    std::chrono::steady_clock::time_point expiryTime;

    Session(const std::string& id, const std::string& sessionData, int ttlSeconds)
        : sessionId(id), data(sessionData) {
        expiryTime = std::chrono::steady_clock::now() + std::chrono::seconds(ttlSeconds);
    }

    bool isValid() const {
        return std::chrono::steady_clock::now() < expiryTime;
    }
};

class SessionCache {
private:
    std::unordered_map<std::string, std::shared_ptr<Session>> cache;

public:
    void createSession(const std::string& sessionId, const std::string& data, int ttlSeconds) {
        auto session = std::make_shared<Session>(sessionId, data, ttlSeconds);
        cache[sessionId] = session;
    }

    std::string accessSession(const std::string& sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            if (it->second->isValid()) {
                return it->second->data;
            } else {
                // Session expired, but keep the session ID in the cache for quick re-initialization
                cache.erase(it);
            }
        }
        return ""; // Return empty string if session does not exist or has expired
    }

    void invalidateSession(const std::string& sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            cache.erase(it);
        }
    }
};

